import{_ as a,o as e,c as n,a2 as p}from"./chunks/framework.C24VBsJ9.js";const u=JSON.parse('{"title":"镜像、分区与文件系统","description":"","frontmatter":{"title":"镜像、分区与文件系统"},"headers":[],"relativePath":"tutorial/flash/02_image_partition_filesystem_basics.md","filePath":"tutorial/flash/02_image_partition_filesystem_basics.md","lastUpdated":1781369075000}'),i={name:"tutorial/flash/02_image_partition_filesystem_basics.md"};function l(t,s,o,d,c,r){return e(),n("div",null,[...s[0]||(s[0]=[p(`<h1 id="镜像、分区和文件系统-img-到底是什么" tabindex="-1">镜像、分区和文件系统 - <code>.img</code> 到底是什么 <a class="header-anchor" href="#镜像、分区和文件系统-img-到底是什么" aria-label="Permalink to &quot;镜像、分区和文件系统 - \`.img\` 到底是什么&quot;">​</a></h1><h2 id="前言-它不是一个文件夹压缩包" tabindex="-1">前言：它不是一个文件夹压缩包 <a class="header-anchor" href="#前言-它不是一个文件夹压缩包" aria-label="Permalink to &quot;前言：它不是一个文件夹压缩包&quot;">​</a></h2><p>很多人第一次接触 <code>.img</code> 时，会下意识把它当成压缩包。这也很正常。因为我们平时看到 <code>.zip</code>、<code>.tar.gz</code>，里面都是一堆文件；看到 <code>rootfs.tar.gz</code>，也确实可以解开得到一个根文件系统目录。</p><p>但这里的 <code>imx6ull-aes-sd.img</code> 或 <code>imx6ull-aes-emmc.img</code> 不是这种东西。</p><p>它不是“把 boot 目录和 rootfs 目录压成一个包”。它更像是把一整张 SD 卡从第 0 字节开始复制成了一个普通文件。</p><p>换句话说：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>.tar.gz 关心的是文件。</span></span>
<span class="line"><span>.img 关心的是整块盘的字节布局。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>理解了这一点，后面很多命令就不奇怪了。<code>sfdisk -d xxx.img</code> 能看分区表，是因为这个 <code>.img</code> 里面真的有分区表。<code>dd</code> 能把它写进 SD 卡，是因为它本来就是按整盘布局生成的。</p><h2 id="从整盘到文件-中间有几层" tabindex="-1">从整盘到文件：中间有几层 <a class="header-anchor" href="#从整盘到文件-中间有几层" aria-label="Permalink to &quot;从整盘到文件：中间有几层&quot;">​</a></h2><p>我们先用一个层级把概念摆正：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>整盘设备</span></span>
<span class="line"><span>└── 分区表</span></span>
<span class="line"><span>    ├── 分区 1</span></span>
<span class="line"><span>    │   └── 文件系统</span></span>
<span class="line"><span>    │       ├── zImage</span></span>
<span class="line"><span>    │       └── imx6ull-aes.dtb</span></span>
<span class="line"><span>    └── 分区 2</span></span>
<span class="line"><span>        └── 文件系统</span></span>
<span class="line"><span>            ├── /bin</span></span>
<span class="line"><span>            ├── /etc</span></span>
<span class="line"><span>            └── /lib</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><p>这几层不要混：</p><p>整盘设备是一块完整存储，例如一张 SD 卡，或者一颗 eMMC。分区表记录这块盘上有哪些分区，每个分区从哪里开始，到哪里结束。</p><p>分区是一段连续的存储范围。文件系统是在分区里面组织文件的一套格式，比如 ext4。文件才是我们平时能 <code>ls</code>、<code>cp</code>、<code>cat</code> 的东西，比如 <code>zImage</code>、<code>.dtb</code>、<code>/etc/inittab</code>。</p><p>如果把这几层混了，就会出现很典型的误会：以为把 <code>u-boot-dtb.imx</code> 拷进 boot 分区，板子下次上电就会从它启动。实际上不会，因为项目里的 U-Boot 不属于 boot 分区里的普通文件。</p><h2 id="mbr-是做什么的" tabindex="-1">MBR 是做什么的 <a class="header-anchor" href="#mbr-是做什么的" aria-label="Permalink to &quot;MBR 是做什么的&quot;">​</a></h2><p>MBR 可以先简单理解成一种老派但够用的分区表格式。</p><p>它放在整盘的开头，告诉系统：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>第 1 个分区从哪个扇区开始，有多大</span></span>
<span class="line"><span>第 2 个分区从哪个扇区开始，有多大</span></span>
<span class="line"><span>每个分区是什么类型</span></span>
<span class="line"><span>哪个分区带 bootable 标记</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>当前镜像脚本会写一个 DOS/MBR 风格的分区表。你用下面命令看镜像：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sfdisk</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> out/release-latest/images/imx6ull-aes-emmc.img</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>能看到类似：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>label: dos</span></span>
<span class="line"><span>unit: sectors</span></span>
<span class="line"><span></span></span>
<span class="line"><span>...img1 : start=32768, size=131072, type=83, bootable</span></span>
<span class="line"><span>...img2 : start=163840, size=..., type=83</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>这里 <code>start=32768</code> 的意思是第 1 个分区从第 32768 个扇区开始。一个扇区按 512 字节算，正好是 16 MiB。</p><p>这就是为什么 <code>.img</code> 可以被 <code>sfdisk</code> 读懂。它虽然是一个普通文件，但文件开头的内容按整盘格式写好了。</p><h2 id="boot-分区和-rootfs-分区" tabindex="-1">boot 分区和 rootfs 分区 <a class="header-anchor" href="#boot-分区和-rootfs-分区" aria-label="Permalink to &quot;boot 分区和 rootfs 分区&quot;">​</a></h2><p>当前镜像里有两个分区。</p><p>第 1 个是 boot 分区。它放启动 Linux 需要的普通文件：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>zImage</span></span>
<span class="line"><span>imx6ull-aes.dtb</span></span>
<span class="line"><span>boot.cmd</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p><code>zImage</code> 是 Linux 内核镜像。<code>.dtb</code> 是设备树，告诉内核这块板子的硬件长什么样。<code>boot.cmd</code> 记录脚本为这个镜像生成的启动命令。</p><p>第 2 个是 rootfs 分区。Linux 内核启动后，会把它挂载成 <code>/</code>：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/</span></span>
<span class="line"><span>├── bin</span></span>
<span class="line"><span>├── etc</span></span>
<span class="line"><span>├── lib</span></span>
<span class="line"><span>└── ...</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>这就是用户空间。BusyBox、init 脚本、配置文件、你后续放进去的应用，都会在 rootfs 里。</p><p>所以启动链路里有一个很自然的顺序：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>U-Boot 读取 boot 分区里的 zImage 和 DTB</span></span>
<span class="line"><span>Linux 内核启动</span></span>
<span class="line"><span>Linux 挂载 rootfs 分区作为根目录</span></span>
<span class="line"><span>进入用户空间</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h2 id="文件系统是什么" tabindex="-1">文件系统是什么 <a class="header-anchor" href="#文件系统是什么" aria-label="Permalink to &quot;文件系统是什么&quot;">​</a></h2><p>分区只是“一段空间”。要在这段空间里放文件，还需要文件系统。</p><p>当前脚本把 boot 分区和 rootfs 分区都做成 ext4。这样 U-Boot 可以用 <code>ext4load</code> 读取内核和设备树，Linux 也能直接挂载 rootfs。</p><p>ext4 文件系统负责回答这些问题：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>这个目录里有哪些文件？</span></span>
<span class="line"><span>这个文件的数据块在哪里？</span></span>
<span class="line"><span>这个文件权限是什么？</span></span>
<span class="line"><span>软链接指向哪里？</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>也就是说，<code>zImage</code> 能以文件形式存在，是因为 boot 分区里面有 ext4 文件系统。<code>/etc/inittab</code> 能被 <code>cat</code>，也是因为 rootfs 分区里面有 ext4 文件系统。</p><p>脚本用 <code>mke2fs -d</code> 生成 ext4 文件系统镜像，这样可以把一个目录直接灌进文件系统里，不需要 <code>sudo mount</code>。后面脚本拆解章节会细讲这件事。</p><h2 id="u-boot-raw-区域不是普通文件" tabindex="-1">U-Boot raw 区域不是普通文件 <a class="header-anchor" href="#u-boot-raw-区域不是普通文件" aria-label="Permalink to &quot;U-Boot raw 区域不是普通文件&quot;">​</a></h2><p>现在回到最容易混的地方：U-Boot。</p><p>项目里的 <code>u-boot-dtb.imx</code> 不放在 boot 分区里作为普通文件启动。镜像脚本会把它写到整盘偏移 1 KiB 的位置：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>offset 1 KiB -&gt; u-boot-dtb.imx</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这段区域在分区前面，属于 raw disk 区域。</p><p>raw 的意思可以先理解成：不经过文件系统，直接按字节或扇区写。这里没有文件名，也没有目录。你不能在 Linux 挂载 boot 分区后 <code>ls</code> 出“1 KiB 偏移处的 U-Boot”。它不在文件系统里。</p><p>这就是为什么我们要区分：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>zImage / DTB：boot 分区里的普通文件</span></span>
<span class="line"><span>u-boot-dtb.imx：整盘 raw 区域里的启动镜像</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>把 <code>zImage</code> 拷到 boot 分区，是文件操作。</p><p>把 <code>u-boot-dtb.imx</code> 写到 1 KiB，是 raw 写盘操作。</p><p>这两件事不在同一层。</p><h2 id="为什么-sfdisk-能看-img" tabindex="-1">为什么 sfdisk 能看 .img <a class="header-anchor" href="#为什么-sfdisk-能看-img" aria-label="Permalink to &quot;为什么 sfdisk 能看 .img&quot;">​</a></h2><p><code>sfdisk</code> 不是只能看真实磁盘。只要一个文件的内容按“整盘布局”组织，它也能读。</p><p>所以这条命令：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sfdisk</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> out/release-latest/images/imx6ull-aes-sd.img</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>本质上是在问：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>这个文件开头有没有我认识的分区表？</span></span>
<span class="line"><span>如果有，每个分区从哪里开始，有多大？</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>它不会挂载分区，也不会读 ext4 里的文件。它只是读分区表。</p><p>如果你想看文件系统层面的信息，可以用更偏文件系统的工具，比如：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dumpe2fs</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -h</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> boot.ext4</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">debugfs</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -R</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;ls -l /&#39;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> boot.ext4</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>这些命令的层次就不一样了。<code>sfdisk</code> 看整盘分区表，<code>dumpe2fs</code> 和 <code>debugfs</code> 看 ext4 文件系统。</p><h2 id="为什么完整镜像要写整盘" tabindex="-1">为什么完整镜像要写整盘 <a class="header-anchor" href="#为什么完整镜像要写整盘" aria-label="Permalink to &quot;为什么完整镜像要写整盘&quot;">​</a></h2><p>现在就能解释上一章那句话了。</p><p>完整 <code>.img</code> 里面同时包含：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>整盘前面的 raw U-Boot</span></span>
<span class="line"><span>整盘前面的 MBR 分区表</span></span>
<span class="line"><span>第 1 分区的 ext4 文件系统</span></span>
<span class="line"><span>第 2 分区的 ext4 文件系统</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>所以它必须从目标设备的第 0 字节开始写。</p><p>写到整盘设备：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>of=/dev/sdb</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>意思是把这些层级完整放回一张真实 SD 卡。</p><p>写到分区设备：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>of=/dev/sdb1</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>意思是把整盘布局塞进第 1 个分区内部。这样外层分区表、raw U-Boot 位置都不对。</p><p>这也是为什么很多教程会反复强调：看清楚 <code>lsblk</code>，确认目标是 <code>disk</code>，不是 <code>part</code>。</p><h2 id="小结" tabindex="-1">小结 <a class="header-anchor" href="#小结" aria-label="Permalink to &quot;小结&quot;">​</a></h2><p>这一章把 <code>.img</code> 拆成了几层：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>整盘</span></span>
<span class="line"><span>→ 分区表</span></span>
<span class="line"><span>→ 分区</span></span>
<span class="line"><span>→ 文件系统</span></span>
<span class="line"><span>→ 文件</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p><code>zImage</code>、DTB、rootfs 里的内容，都是文件系统里的普通文件。U-Boot 则写在整盘前面的 raw 区域，不属于 boot 分区。</p><p>下一章我们继续看 i.MX6ULL 的启动链路。重点解决一个问题：为什么项目脚本偏偏把 <code>u-boot-dtb.imx</code> 写到 1 KiB，而 boot 分区又从 16 MiB 开始。</p><p><strong>下一步：</strong> 阅读 <a href="./03_imx6ull_boot_flow_and_offsets">03_imx6ull_boot_flow_and_offsets.md</a>，理解 i.MX6ULL 启动链路和这些偏移的意义。</p>`,81)])])}const h=a(i,[["render",l]]);export{u as __pageData,h as default};
